We did close FD 4, but `sys_accept` should be able to either open a new FD number or re-use FD 4 (native run re-uses 4). Currently, it tries to reopen FD 4, but we haven't purged FD 4 from the available new FDs for open files list when we close it (or something, I forget exactly), so there is an error when trying open a new FD after closing.

Here is a C program that might be a bit more concrete:

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <netinet/in.h>
#include <signal.h>
#include <string.h>

#define PORT 8081
#define BUFFER_SIZE 80
#define TRUE 0
#define FALSE 1

int server_fd, new_client;
struct sockaddr_in address;

int setupServer()
{
    int opt = 1; // reuse address

    // create socket file descriptor, attach to 8081
    server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR | SO_REUSEPORT, &opt, sizeof(opt))) {
      printf("Cannot setsockopt\n");
      return FALSE;
    }
    address.sin_family = AF_INET;
    address.sin_addr.s_addr = INADDR_ANY;
    address.sin_port = htons(PORT);
    if (bind(server_fd, (struct sockaddr *)&address, sizeof(address))) {
      printf("Cannot bind\n");
      return FALSE;
    }

    printf("Listening on port %i...\n", PORT);
    return TRUE;
}

int main() {
  int setup = setupServer();
  if (setup != 0) {
    return 1;
  }

  int addrlen = sizeof(address);

  listen(server_fd, 10);
  printf("Listening on fd %d...\n", server_fd);
  new_client = accept(server_fd, (struct sockaddr *)&address, (socklen_t *)&addrlen);
  printf("Accepting on fd %d...\n", new_client);
  close(new_client);
  new_client = accept(server_fd, (struct sockaddr *)&address, (socklen_t *)&addrlen);
  printf("Accepting on fd %d...\n", new_client);
  close(new_client);
  close(server_fd);
}
```

